compliant:
#include <unistd.h>
#include <stdio.h>

void change_dir() {
    const char* target_dir = "/some/path";

    // Compliant: checking return value
    if (chdir(target_dir) != 0) {
        perror("chdir failed");
        return;
    }

    int fd = open(target_dir, O_RDONLY | O_DIRECTORY);
    if (fd != -1) {
        if (fchdir(fd) != 0) {
            perror("fchdir failed");
        }
        close(fd);
    }
}
